const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function addWithoutCarry(a, b) {
    let result = 0, multiplier = 1;
    while (a > 0 || b > 0) {
        let sum = (a % 10) + (b % 10);
        result += (sum % 10) * multiplier;
        a = Math.floor(a / 10);
        b = Math.floor(b / 10);
        multiplier *= 10;
    }
    return result;
}

let T = parseInt(lines[idx++]);
